solutions.javascript:
// Solution
function correctGridLayout(gridDefinition) {
    let rows = gridDefinition.split('grid-template-rows:');
    let correctedRows = [];
    for (let row of rows) {
        let rowHeight = row.split(' ')[1];
        if (rowHeight.includes('px')) {
            correctedRows.push(rowHeight);
        } else {
            let maxRowHeight = Math.max(...rows.map(row => row.split(' ')[1]));
            correctedRows.push(maxRowHeight);
        }
    }
    return 'grid-template-columns: 100px 200px 300px; grid-template-rows: ' + correctedRows.join(' ');
}

solutions.python:
class Solution:
    def correct_grid_layout(self, grid_definition) -> str:
        rows = grid_definition.split('grid-template-rows:');
        corrected_rows = [];
        for row in rows:
            row_height = row.split(' ')[1];
            if 'px' in row_height:
                corrected_rows.append(row_height);
            else:
                max_row_height = max(row.split(' ')[1] for row in rows)
                corrected_rows.append(max_row_height)
        return 'grid-template-columns: 100px 200px 300px; grid-template-rows: ' + ' '.join(corrected_rows);
